// @feature:recents Recently-added notes panel in search modal.
// Shows when the modal opens with no query. Hides when user types.
// Fetches /notes/recents.json (generated by generate_recents.py at publish time).
(function () {
  var RECENTS_URL = "/notes/recents.json";
  var MAX_DISPLAY = 5;
  var THREE_DAYS_MS = 3 * 24 * 60 * 60 * 1000;

  var recentsCache = null;

  function loadRecents() {
    if (recentsCache !== null) return Promise.resolve(recentsCache);
    return fetch(RECENTS_URL)
      .then(function (res) { return res.ok ? res.json() : []; })
      .catch(function () { return []; })
      .then(function (data) { recentsCache = data; return data; });
  }

  function relativeTime(isoString) {
    var diff = Date.now() - new Date(isoString).getTime();
    var days = Math.floor(diff / 86400000);
    if (days === 0) return "today";
    if (days === 1) return "yesterday";
    return days + " days ago";
  }

  function showRecentsPanel() {
    var container = document.getElementById("search-modal-results");
    var input = document.getElementById("search-modal-input");
    if (!container || !input) return;

    loadRecents().then(function (recents) {
      // Re-check: user may have typed while fetch was in flight
      if (input.value.trim() !== "") return;

      var now = Date.now();
      var within3 = recents.filter(function (r) {
        return now - new Date(r.mtime_iso).getTime() <= THREE_DAYS_MS;
      });
      var items = (within3.length > 0 ? within3 : recents).slice(0, MAX_DISPLAY);
      if (items.length === 0) return;

      container.innerHTML = "";

      var label = document.createElement("div");
      label.className = "recents-label";
      label.textContent = "Recently Added";
      container.appendChild(label);

      items.forEach(function (entry, i) {
        var item = document.createElement("a");
        item.href = entry.url;
        item.className = "search-result-item";
        item.setAttribute("data-index", String(i));

        var title = document.createElement("div");
        title.className = "search-result-title";
        title.textContent = entry.title || "";
        item.appendChild(title);

        if (entry.folder) {
          var folder = document.createElement("div");
          folder.className = "search-result-folder";
          folder.textContent = entry.folder;
          item.appendChild(folder);
        }

        var snip = document.createElement("div");
        snip.className = "search-result-snippet";
        snip.textContent = relativeTime(entry.mtime_iso);
        item.appendChild(snip);

        item.addEventListener("click", function () {
          var overlay = document.getElementById("search-overlay");
          if (overlay) {
            overlay.classList.add("hidden");
            overlay.classList.remove("closing");
          }
        });

        container.appendChild(item);
      });
    });
  }

  function watchOverlayVisibility(overlay) {
    var observer = new MutationObserver(function (mutations) {
      for (var i = 0; i < mutations.length; i++) {
        if (mutations[i].attributeName === "class") {
          var el = mutations[i].target;
          if (!el.classList.contains("hidden") && !el.classList.contains("closing")) {
            showRecentsPanel();
          }
        }
      }
    });
    observer.observe(overlay, { attributes: true, attributeFilter: ["class"] });
  }

  function attachInputListener() {
    var input = document.getElementById("search-modal-input");
    if (!input) return;
    input.addEventListener("input", function (e) {
      if (e.target.value.trim() === "") {
        showRecentsPanel();
      }
    });
  }

  function init() {
    // Preload so recents are ready before user opens modal
    loadRecents();

    var overlay = document.getElementById("search-overlay");
    if (overlay) {
      watchOverlayVisibility(overlay);
      attachInputListener();
    } else {
      // Overlay is created lazily on first modal open — watch for it
      var bodyObserver = new MutationObserver(function (mutations) {
        for (var i = 0; i < mutations.length; i++) {
          var nodes = mutations[i].addedNodes;
          for (var j = 0; j < nodes.length; j++) {
            if (nodes[j].id === "search-overlay") {
              bodyObserver.disconnect();
              watchOverlayVisibility(nodes[j]);
              attachInputListener();
              return;
            }
          }
        }
      });
      bodyObserver.observe(document.body, { childList: true });
    }
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    init();
  }
})();
